openscad:
case_dia = 40; // [30:1:60]
case_height = 8; // [5:1:15]
dial_dia = 34; // [25:1:55]
bezel_height = 2; // [1:0.5:5]
hand_length_h = 10; // [6:1:18]
hand_length_m = 13; // [8:1:20]
hand_length_s = 15; // [10:1:22]
date_window = 5; // [3:0.5:8]
$fn = 60;

module watch() {
    // Case
    color("silver")
    difference() {
        cylinder(d=case_dia, h=case_height);
        translate([0,0,case_height-1])
            cylinder(d=case_dia-3, h=bezel_height+1);
    }

    // Dial
    color("white")
    translate([0,0,case_height-1.5])
        cylinder(d=dial_dia, h=1.5);

    // Hour markers
    color("black")
    for (i = [0:11]) {
        rotate([0,0,i*30])
            translate([dial_dia/2-4, -0.6, case_height-1.6])
                cube([3.5, 1.2, 1.6]);
    }

    // Date window
    color("white")
    translate([dial_dia/2-8, -date_window/2, case_height-1.6])
        cube([date_window+2, date_window, 1.7]);
    color("black")
    translate([dial_dia/2-7, -1.5, case_height-1.5])
        linear_extrude(1.6)
            text("31", size=3, halign="center", valign="center");

    // Hour hand
    color("black")
    rotate([0,0,50])
        translate([0,0,case_height-0.5])
            linear_extrude(2)
                polygon(points=[[0,-0.8],[hand_length_h, -0.4],[hand_length_h,0.4],[0,0.8]]);

    // Minute hand
    color("black")
    rotate([0,0,20])
        translate([0,0,case_height-0.3])
            linear_extrude(2)
                polygon(points=[[0,-0.6],[hand_length_m,-0.3],[hand_length_m,0.3],[0,0.6]]);

    // Second hand
    color("red")
    rotate([0,0,150])
        translate([0,0,case_height-0.1])
            linear_extrude(2.2)
                polygon(points=[[0,-0.3],[-2,-0.15],[-2,0.15],[hand_length_s,0.15],[hand_length_s,-0.15]]);
}

watch();
